INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Pub/Sub Messaging$q$, $q$Channel-based publish/subscribe messaging with guaranteed ordering and delivery across a global edge network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Ably Chat$q$, $q$Purpose-built chat API with typing indicators, reactions, threads, and moderation hooks for building chat experiences quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Presence$q$, $q$Track who is online in a channel or a collaborative space in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Message History and Stream Resume$q$, $q$Replay missed messages and recover connection state after disconnects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Multi-Protocol Support$q$, $q$REST, WebSocket, MQTT, and SSE support so backends and IoT devices on different stacks can connect.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Push Notifications$q$, $q$Deliver native push notifications to mobile and web clients through the same platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Integrations$q$, $q$Stream events into Kafka, AWS Lambda, Kinesis, Google Cloud Functions, and other systems via built-in rules and firehose.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Enterprise-Grade Reliability$q$, $q$Up to 99.999 percent uptime SLA and a formally verified global network architecture.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Deep reliability guarantees backed by a formally modeled network$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Generous free tier suitable for prototypes and low-volume production apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Broad SDK and protocol coverage across many languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Purpose-built products like Chat and Spaces reduce build time for common realtime UX patterns$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Enterprise support and SLAs for mission-critical use cases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Usage-based pricing can become expensive at high message or connection volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Some advanced features and support SLAs are gated behind Pro and Enterprise plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Pub/sub concepts add a learning curve for teams new to realtime architecture$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$What is Ably used for?$q$, $q$Ably is used to add realtime features such as chat, live notifications, collaborative cursors, live data dashboards, multiplayer state sync, and IoT telemetry streaming to applications without running custom WebSocket infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Does Ably have a free plan?$q$, $q$Yes. Ably's free plan supports up to 200 concurrent connections, 500 messages per second, and 6 million messages per month, enough for prototypes and many small production apps.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$How is Ably priced?$q$, $q$Ably charges a monthly platform fee on paid plans plus usage-based charges for messages, connection minutes, channel minutes, and data transfer, or alternatively bills by monthly active users. Enterprise plans use custom contracts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$What protocols does Ably support?$q$, $q$Ably supports REST, WebSocket, MQTT, and Server-Sent Events, and provides client SDKs for languages including JavaScript, Python, Java, Swift, and Kotlin.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Is Ably a replacement for Socket.IO or Firebase Realtime Database?$q$, $q$Ably can replace self-managed WebSocket layers and offers similar realtime capability to Firebase's realtime features, but with stronger delivery guarantees, multi-protocol support, and enterprise SLAs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Who founded Ably and when?$q$, $q$Ably was founded by Matthew O'Riordan and Dr. Paddy Byers, with the company established in 2013 and its core platform launching in 2016.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Where is Ably headquartered?$q$, $q$Ably is headquartered in London, United Kingdom.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Does Ably offer uptime guarantees?$q$, $q$Yes, Enterprise plans include uptime SLAs of up to 99.999 percent, along with 24/7 mission-critical support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Realtime Chat and Collaboration$q$, $q$Engineering teams building in-app chat, live comments, or collaborative editing features use Ably Chat and Spaces to add presence, typing indicators, and multiplayer cursors without building the underlying infrastructure.$q$, $q$Product and engineering teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Live Data and Trading Dashboards$q$, $q$Fintech and media companies stream live prices, odds, or sports scores to thousands of concurrent viewers using Ably's pub/sub channels with guaranteed message ordering.$q$, $q$Fintech and media platform engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$IoT and Device Telemetry$q$, $q$IoT companies use Ably's MQTT support and message history to reliably collect and distribute sensor data from distributed devices, even through unstable network connections.$q$, $q$IoT and industrial software teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Free$q$, $q$$0$q$, $q$no commitment$q$, NULL, $q$["200 concurrent connections","500 messages per second","6 million messages per month","Community support","Access to all Ably products"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Standard$q$, $q$$29/month plus usage$q$, $q$monthly$q$, NULL, $q$["10k concurrent channels","10k connections","2.5k messages per second","1-day email support SLA"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Pro$q$, $q$$399/month plus usage$q$, $q$monthly$q$, NULL, $q$["50k concurrent channels","50k connections","10k messages per second","4-hour email support SLA","Datadog lite integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Unlimited channels, connections, and messages","24/7 mission-critical support","Up to 99.999 percent uptime SLA","Committed use discounts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$overview$q$, $q$What Is Ably$q$, 2, ARRAY[$q$Ably is a managed realtime infrastructure platform that lets developers add pub/sub messaging, chat, presence, and live data streaming to applications without building and scaling their own WebSocket or long-polling servers. Founded in London in 2013 by Matthew O'Riordan and Dr. Paddy Byers, the company spent several years engineering a globally distributed edge network before launching its core platform in 2016.$q$, $q$Rather than a single product, Ably operates as a platform of realtime primitives: channel-based publish and subscribe, presence tracking, message history, and connection recovery, all exposed through REST, WebSocket, MQTT, and SSE interfaces. On top of this core, Ably has built specific products such as Ably Chat and Ably Spaces to shortcut common realtime UX patterns like typing indicators and multiplayer cursors.$q$, $q$The platform is aimed at engineering teams, from early-stage startups to large fintech, media, and gaming companies, that need dependable message delivery and ordering guarantees at scale, without operating the underlying infrastructure themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ably's pub/sub core guarantees message ordering and delivery across a globally redundant edge network, with message history and stream resume so clients can recover missed data after a disconnect. Presence tracking lets applications show who is online in a channel or collaborative space in real time.$q$, $q$Purpose-built products reduce the engineering lift for common patterns: Ably Chat provides a ready-made chat API with reactions and moderation hooks, and Ably Spaces handles multiplayer presence and cursor sharing for collaborative tools.$q$, $q$Ably also supports push notifications, multiple protocols (REST, WebSocket, MQTT, SSE), and integrations that stream events into systems like Kafka, AWS Lambda, and Kinesis, making it usable as both a frontend realtime layer and a backend event distribution system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d481ce42-0ced-4647-b358-b4f024cda820', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Ably offers a free tier covering roughly 200 concurrent connections, 500 messages per second, and 6 million messages per month, suitable for prototypes and small production apps. Paid plans start with Standard at $29 per month plus usage, and Pro at $399 per month plus usage, each raising channel, connection, and throughput limits and adding faster support SLAs.$q$, $q$Usage-based charges apply on top of the monthly platform fee for messages, connection minutes, channel minutes, and data transfer, with per-unit rates dropping at higher volumes. Billing can alternatively be based on monthly active users for consumer apps with unpredictable traffic patterns.$q$, $q$Enterprise plans are custom-priced and add unlimited capacity, 24/7 mission-critical support, uptime SLAs up to 99.999 percent, and committed-use discounts, typically negotiated directly with Ably's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Course Authoring and Content Support$q$, $q$Build lessons natively with Absorb Create or import SCORM, xAPI, and AICC courses from other authoring tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Compliance Tracking and Reporting$q$, $q$Automate certification expiry, renewal reminders, and audit-ready compliance reports.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$AI-Powered Recommendations$q$, $q$AI-generated content summaries and personalized course recommendations based on learner role and activity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Multi-Audience Portals$q$, $q$Deliver branded, separate learning portals for employees, customers, and partners from a single LMS instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Native Mobile Apps$q$, $q$iOS and Android apps with offline course access for distributed and field-based learners.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Gamification and Social Learning$q$, $q$Badges, leaderboards, points, and discussion tools to boost learner engagement.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$E-Commerce$q$, $q$Sell courses, bundles, and certifications directly through the platform for external training revenue.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Integrations$q$, $q$Connects with HRIS systems, SSO providers, video conferencing tools, and third-party content libraries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Strong compliance and certification tracking suited to regulated industries$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Supports both internal employee training and external customer or partner learning from one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Native mobile apps with offline access for field and frontline workers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Established vendor with over two decades of LMS focus and broad third-party integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$AI features for content summarization and personalized recommendations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Pricing is not published and requires a sales quote, making budget comparison harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Cost can rise significantly as active learner counts grow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Some advanced features like API access and custom branding are limited to higher-tier editions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Initial setup and content migration can require dedicated implementation time$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$What is Absorb LMS?$q$, $q$Absorb LMS is a cloud-based learning management system that lets organizations create, deliver, and track online and blended training for employees, customers, and partners.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$How much does Absorb LMS cost?$q$, $q$Absorb LMS does not publish fixed pricing. It is quoted per active learner per year based on the edition, Core, Pro, or Enterprise, and deployment needs, so pricing requires a custom quote from Absorb's sales team.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Does Absorb LMS support SCORM and xAPI content?$q$, $q$Yes, Absorb LMS supports SCORM, xAPI (Tin Can), and AICC standards for importing existing e-learning content, alongside its native Absorb Create authoring tool.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Can Absorb LMS be used for external training, not just employees?$q$, $q$Yes, Absorb LMS supports multi-audience, multi-portal deployments so organizations can train employees, customers, and channel partners separately, including e-commerce for selling courses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Does Absorb LMS have a mobile app?$q$, $q$Yes, Absorb LMS offers native iOS and Android apps with offline access for learners without consistent internet connectivity.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Who owns Absorb LMS?$q$, $q$Absorb LMS is developed by Absorb Software, a company founded in 2003 and headquartered in Calgary, Alberta, Canada.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$What industries use Absorb LMS?$q$, $q$Absorb LMS is widely used in healthcare, financial services, manufacturing, retail, and non-profit sectors, particularly where compliance training and certification tracking are required.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$What are Absorb LMS's main competitors?$q$, $q$Common alternatives include Cornerstone OnDemand, Docebo, TalentLMS, 360Learning, and Litmos.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Employee Onboarding and Compliance Training$q$, $q$HR and L&D teams use Absorb LMS to onboard new hires and deliver mandatory compliance courses with automated tracking of certification renewals and audit trails.$q$, $q$HR and learning and development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Customer and Partner Education$q$, $q$Companies use Absorb's multi-portal capability and e-commerce features to train and certify external customers, resellers, and channel partners, sometimes generating revenue from paid courses.$q$, $q$Customer education and channel enablement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Extended Enterprise Skills Development$q$, $q$Large organizations use Absorb's AI-driven recommendations and gamification to drive ongoing skills development and engagement across a distributed, frontline, or remote workforce.$q$, $q$Enterprise training and people development leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Core$q$, $q$Custom quote$q$, $q$per active learner, annual$q$, NULL, $q$["Course creation and delivery","Learner enrollment and tracking","Basic reporting","Mobile access","Standard HRIS and SSO integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Pro$q$, $q$Custom quote$q$, $q$per active learner, annual$q$, NULL, $q$["Advanced analytics and reporting","AI content recommendations","Custom branding","Advanced API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$Enterprise$q$, $q$Custom quote$q$, $q$per active learner, annual$q$, NULL, $q$["Dedicated account management","Premium support SLAs","Advanced security and compliance","Custom integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$overview$q$, $q$What Is Absorb LMS$q$, 2, ARRAY[$q$Absorb LMS is a cloud-based learning management system used by organizations to create, deliver, and track online and blended training for employees, customers, and partners. Founded in 2003 and headquartered in Calgary, Alberta, Canada, Absorb Software serves more than 3,500 organizations across industries including healthcare, financial services, and manufacturing.$q$, $q$The platform supports both internal training use cases, like onboarding and compliance, and external audiences such as customers and channel partners, using separate branded portals from a single LMS instance. It supports SCORM, xAPI, and AICC content standards for importing existing courses, alongside its native Absorb Create authoring tool.$q$, $q$Absorb has added AI-driven capabilities including automated content summarization and personalized course recommendations, positioning it as a modern alternative to legacy corporate LMS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Absorb LMS centers on course authoring and delivery, compliance tracking with automated certification renewal reminders, and audit-ready reporting for regulated industries. Native mobile apps with offline access support field and frontline workers who lack consistent connectivity.$q$, $q$Gamification features like badges, leaderboards, and points, along with social and discussion tools, are built in to boost learner engagement, while e-commerce functionality lets organizations sell courses and certifications directly to external audiences.$q$, $q$The platform integrates with HRIS systems, SSO providers, video conferencing tools, and third-party content libraries, and its AI features generate content summaries and recommend relevant courses based on learner role and activity.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae54ef19-4ee9-49ce-8b0c-384fc84052de', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Absorb LMS does not publish fixed pricing. It is sold in tiered editions, commonly Core, Pro, and Enterprise, with cost quoted per active learner per year based on the features and deployment complexity required.$q$, $q$Prospective buyers must contact Absorb's sales team for a custom quote; third-party spend benchmarking data suggests small and mid-sized deployments average in the tens of thousands of dollars per year, with enterprise deployments considerably higher.$q$, $q$Higher tiers unlock advanced analytics, AI-powered recommendations, custom branding, and advanced API access, while the Enterprise tier adds dedicated account management and premium support SLAs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Git-Style Branching for Design Files$q$, $q$Create branches, request reviews, and merge changes to Sketch files with full version history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Visual Diffs$q$, $q$Compare design file versions side by side to see exactly what changed between revisions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Design Notebooks$q$, $q$Document design decisions and gather structured feedback in a dedicated workspace connected to your files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Figma and Sketch Integration$q$, $q$Connects to both major design tools rather than locking teams into one.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Review Workflows$q$, $q$Request and track design reviews with inline comments and approval tracking before merging changes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Developer Handoff (Inspect)$q$, $q$Generate specs, assets, and code snippets for engineers directly from design files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Jira and GitHub Integration$q$, $q$Link design work to engineering tickets and pull requests for cross-functional traceability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$SSO/SAML and Advanced Permissions$q$, $q$Enterprise-grade access controls and fine-grained roles on higher-tier plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Brings familiar Git-like workflows, branch, review, merge, to design files$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Free tier and unlimited viewers on every plan lowers cost for stakeholders who only need to view work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Works with both Sketch and Figma rather than being locked to one tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Strong review and documentation tooling for teams with audit or compliance needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Long track record and enterprise adoption, used by roughly a third of the Fortune 500 per the company$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Sketch-specific version control is less relevant as many teams have moved to Figma's own native version history$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Per-contributor pricing can add up for larger design teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Two distinct product lines, Notebooks and Branches, can be confusing to evaluate$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Some workflow-automation features are marked as in-development rather than fully available$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$What is Abstract used for?$q$, $q$Abstract is used by design teams to apply version control, branching, and structured review workflows to design files, similar to how developers use Git for code, and to document design decisions in a shared workspace.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Does Abstract work with Figma?$q$, $q$Yes, Abstract's Notebooks product integrates with Figma as well as Sketch, so teams are not limited to one design tool.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Is Abstract free?$q$, $q$Abstract offers a free-forever plan with limited active notebooks and unlimited viewers; paid Pro and Enterprise plans unlock unlimited notebooks, deeper integrations, and enterprise security features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$How is Abstract priced?$q$, $q$Abstract is priced per contributor per month, billed monthly or annually, with viewers included free on every plan. Enterprise pricing is custom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$When was Abstract founded?$q$, $q$Abstract was founded in 2016 and launched publicly in 2017, headquartered in San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$What is the difference between Abstract Branches and Abstract Notebooks?$q$, $q$Branches is Abstract's original Git-style version control product built specifically for Sketch files, while Notebooks is a broader design documentation and review workspace that connects to Figma, Sketch, GitHub, and Jira.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Who uses Abstract?$q$, $q$Abstract is used primarily by product design teams at mid-size and large companies, including many Fortune 500 organizations, that need structured design version control and review processes.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Does Abstract integrate with developer tools?$q$, $q$Yes, Abstract integrates with GitHub and Jira so design work can be linked to code repositories and engineering tickets.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Design Version Control for Sketch Teams$q$, $q$Design teams still working in Sketch use Abstract's Branches product to track file history, compare versions, and merge changes without overwriting each other's work.$q$, $q$Product design teams using Sketch$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Cross-Tool Design Documentation$q$, $q$Teams that use a mix of Figma and Sketch use Abstract Notebooks to centralize design decisions, feedback, and review status in one place regardless of source tool.$q$, $q$Multi-tool design and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Design-to-Engineering Handoff$q$, $q$Design and engineering teams use Abstract's Inspect and Jira and GitHub integrations to connect finished designs directly to development tickets and specs.$q$, $q$Cross-functional design and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Notebooks Free$q$, $q$Free$q$, $q$forever$q$, NULL, $q$["Up to 3 active notebooks","Unlimited viewers","Figma, Sketch, GitHub, and Jira integrations","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Notebooks Pro$q$, $q$$29/month per contributor billed annually ($32 monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited notebooks","Focused reviews and review tracking","Deep integrations","Project and team insights","SSO/SAML"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Abstract Pro (Branches)$q$, $q$$35/month per contributor billed annually ($44 monthly)$q$, $q$monthly or annual$q$, NULL, $q$["File management and version control up to 250GB storage","Unlimited viewers","Review requests","Inspect tool for specs"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Unlimited storage and seats","Advanced reporting","SSO/SAML","Priority support","Custom terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$overview$q$, $q$What Is Abstract$q$, 2, ARRAY[$q$Abstract is a design version control and collaboration platform founded in 2016 and headquartered in San Francisco. It was originally built to bring Git-style branching, merging, and version history to Sketch design files, at a time when design teams had few reliable tools for tracking changes across a shared file.$q$, $q$Over time, Abstract expanded beyond pure Sketch version control into a broader design documentation and review tool called Notebooks, which works with both Figma and Sketch and connects to development tools like GitHub and Jira.$q$, $q$The company reports over 7,000 companies have used its tools, including roughly a third of the Fortune 500, and it raised a 30 million dollar funding round in 2019.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Abstract's Branches product applies Git-style branching to Sketch files: designers branch off exploratory work, request reviews with inline comments, view visual diffs between versions, and merge approved changes into a master file with full history.$q$, $q$Notebooks extends this to a documentation and review workspace that connects to Figma and Sketch alike, letting teams record design decisions and gather structured feedback in one place regardless of which tool produced the file.$q$, $q$Developer handoff is supported through an Inspect tool that generates specs and assets for engineers, and integrations with GitHub and Jira connect finished design work directly to code repositories and tickets.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4faf985-7c58-4c87-8560-524d88331992', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Abstract is priced per contributor per month, billed monthly or annually, with unlimited viewers included free on every plan. A free-forever tier covers up to three active notebooks for individuals or small teams.$q$, $q$Paid Pro tiers run roughly 29 to 35 dollars per contributor per month depending on the product line, Notebooks or Branches, and unlock unlimited notebooks or up to 250GB of file storage, deeper integrations, and review tracking.$q$, $q$Enterprise plans are custom-priced and add unlimited storage and seats, SSO/SAML, advanced reporting, dedicated account management, and priority support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Email Validation API$q$, $q$Verify email deliverability, syntax, and detect disposable or role-based addresses.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$IP Geolocation API$q$, $q$Resolve IP addresses to location, timezone, currency, and connection type data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Phone Validation API$q$, $q$Validate and format international phone numbers and identify carrier and line type.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Company Enrichment API$q$, $q$Look up company data such as industry, size, and domain by name or domain.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Exchange Rates API$q$, $q$Retrieve current and historical currency exchange rate data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$VAT Validation API$q$, $q$Validate EU VAT numbers and calculate VAT rates for compliance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Holidays API$q$, $q$Retrieve public holiday data for countries worldwide for scheduling and localization.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Email Reputation and Fraud API$q$, $q$Assess email risk signals to support fraud prevention workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Wide catalog of common developer APIs available from a single vendor and account$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Free tier available on every API for testing and non-commercial use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Simple REST integration with clear per-request documentation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Useful for teams that need several auxiliary data checks without vetting multiple vendors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Transparent, self-serve signup without requiring a sales call for standard tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Each API is billed separately, so combined costs across multiple APIs add up quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Free tiers are restricted to non-commercial use, limiting their usefulness for production testing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Annual billing is not consistently self-serve$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Specialized single-purpose competitors may offer better accuracy or pricing for a specific use case$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$What is Abstract API?$q$, $q$Abstract API is a collection of individually sold developer APIs covering tasks like email validation, IP geolocation, phone validation, company enrichment, and exchange rates, aimed at engineering teams that need pre-built data endpoints.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Is Abstract API the same company as Abstract (goabstract.com)?$q$, $q$No. Abstract API (abstractapi.com) is a developer API provider founded in 2020, completely separate from Abstract (goabstract.com), which is a design version-control tool for Sketch and Figma files.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Is Abstract API free?$q$, $q$Each API has a free tier, but free usage is restricted to non-commercial or evaluation purposes. Production use requires a paid subscription on each API used.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$How much does Abstract API cost?$q$, $q$Paid plans start at roughly 17 dollars per month per individual API, with higher tiers unlocking more requests, faster response times, and better data quality; enterprise pricing is custom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Can I use multiple Abstract APIs together?$q$, $q$Yes, but each API, for example Email Validation and IP Geolocation, is billed as a separate subscription, so using several APIs together means paying for each one individually.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Where is Abstract API headquartered?$q$, $q$Abstract API is headquartered in San Francisco, United States.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Does Abstract API offer an SLA?$q$, $q$Enterprise plans advertise up to 99.99 percent SLA along with SSO and SAML support, available via custom quote.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$What programming languages does Abstract API support?$q$, $q$Abstract API is a REST-based service, so it can be called from any language capable of making HTTP requests, and the company provides documentation and code samples for common languages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Signup Form Validation$q$, $q$SaaS products use the Email Validation and Phone Validation APIs to catch fake or malformed contact details at signup, reducing bounce rates and fraud.$q$, $q$Web and mobile product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Location-Based Personalization$q$, $q$E-commerce and content platforms use the IP Geolocation API to localize currency, language, and content based on a visitor's inferred location.$q$, $q$E-commerce and marketing engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$B2B Lead and Company Data Enrichment$q$, $q$Sales and marketing tools use the Company Enrichment API to append firmographic data to leads captured through forms, based on their email domain.$q$, $q$RevOps and sales engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Free$q$, $q$$0 per API$q$, $q$monthly$q$, NULL, $q$["Limited requests per month","Non-commercial use only","Access to core endpoints"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Starter$q$, $q$From about $17/month per API$q$, $q$monthly$q$, NULL, $q$["Higher request volume","Production use allowed","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Growth$q$, $q$Usage-tiered pricing per API$q$, $q$monthly$q$, NULL, $q$["Higher request limits","Faster response times","Improved data quality"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Up to 99.99 percent SLA","SSO and SAML","Dedicated support","Custom request volumes"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$overview$q$, $q$What Is Abstract API$q$, 2, ARRAY[$q$Abstract API is a collection of standalone developer REST APIs covering common backend data tasks, including email validation, IP geolocation, phone validation, company enrichment, exchange rates, and fraud scoring. Founded in 2020 and headquartered in San Francisco, it targets engineering teams that would rather call a pre-built API than build and maintain this logic themselves.$q$, $q$Despite the similar name, Abstract API is a completely separate company from Abstract (goabstract.com), the design version-control tool; Abstract API operates exclusively as a backend data API provider with no design or collaboration features.$q$, $q$Each API is sold, documented, and billed as its own product, so teams typically choose the specific endpoints they need rather than subscribing to a single unified platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Email Validation API checks deliverability, syntax, and disposable or role-based addresses, while the Phone Validation API verifies and formats international numbers and identifies carrier and line type.$q$, $q$The IP Geolocation API resolves IP addresses to location, timezone, and connection type data, and the Company Enrichment API looks up firmographic data by company name or domain, useful for lead enrichment.$q$, $q$Additional APIs cover VAT validation, currency exchange rates, public holidays, and email reputation and fraud scoring, all accessible through simple REST calls with per-API documentation and dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe668cf5-f27d-4d8d-8bd0-f09a6b46b3f6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Every Abstract API endpoint has its own free tier, restricted to non-commercial or evaluation use, and its own paid subscription tiers for production traffic, starting at roughly 17 dollars per month per API.$q$, $q$Because pricing is per API rather than bundled, teams using multiple endpoints together, such as email validation, geolocation, and company enrichment, pay for each subscription separately, which can add up quickly at scale.$q$, $q$Enterprise plans offer custom pricing with SLAs up to 99.99 percent and SSO support across the suite; billing is month-to-month by default with overage fees for exceeding request limits.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Permitting and Licensing$q$, $q$Manage building permits, business licenses, and land-use approvals through configurable workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Code Enforcement$q$, $q$Track violations, inspections, and case resolution for municipal code compliance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Citizen Access Portal$q$, $q$Public-facing self-service portal for residents and contractors to apply, pay fees, and track applications online.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$GIS Mapping$q$, $q$Visualize permits, inspections, and regulated parcels on interactive maps tied to case records.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Environmental Health Management$q$, $q$Manage inspections and compliance for restaurants, pools, and other regulated facilities.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Asset Management$q$, $q$Track and maintain public infrastructure assets alongside permitting and inspection data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Mobile Inspections$q$, $q$Field inspectors use mobile apps to complete and submit inspection results in real time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Reporting and Analytics$q$, $q$Dashboards for tracking permit volumes, review times, and departmental performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Purpose-built for government workflows and public-sector compliance requirements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Long track record, over two decades, with deep coverage of civic use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Citizen-facing self-service portal reduces in-person counter visits for residents and contractors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Highly configurable to match varied municipal code and process requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Available through government procurement contract vehicles, easing public-sector purchasing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Pricing is not published and requires a lengthy sales and procurement process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Implementation can be complex given the breadth of configurable modules$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Legacy configuration options can make the interface feel dated compared to newer govtech entrants$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Best suited to government agencies only, not usable for general private-sector business needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$What is Accela used for?$q$, $q$Accela is government software used by cities, counties, and states to manage permitting, licensing, code enforcement, environmental health inspections, and citizen self-service requests.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Who uses Accela?$q$, $q$Accela is used by local and state government agencies, including planning, building, and public health departments, not by private businesses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$How much does Accela cost?$q$, $q$Accela does not publish pricing. Costs are quoted based on agency size, number of modules deployed, and integration needs, typically through a public-sector procurement process.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Is Accela the same as Accelo?$q$, $q$No. Accela is government permitting and licensing software, while Accelo is a professional services automation platform for private agencies and consultancies. The names are similar but the companies and products are unrelated.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Does Accela offer an online portal for residents?$q$, $q$Yes, Accela Citizen Access is a public-facing portal where residents and contractors can apply for permits, pay fees, schedule inspections, and check application status.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$When was Accela founded?$q$, $q$Accela was founded in 1999 and is headquartered in San Ramon, California.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$What are Accela's main competitors?$q$, $q$Competitors include Tyler Technologies' EnerGov, OpenGov, CityView, and Municity, among other government permitting and licensing software vendors.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Does Accela support mobile inspections?$q$, $q$Yes, field inspectors can use Accela's mobile apps to complete, document, and submit inspection results from the field.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Building Permit Digitization$q$, $q$Building departments use Accela to move permit applications, plan reviews, and inspection scheduling online, reducing processing time and in-person counter visits.$q$, $q$Municipal building and planning departments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Business Licensing and Renewals$q$, $q$Cities use Accela Automation to manage business license applications, renewals, and fee collection through a configurable workflow engine.$q$, $q$City licensing and revenue departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Code Enforcement Case Management$q$, $q$Code enforcement teams use Accela to log violations, track case resolution, and coordinate with GIS data to manage compliance across a jurisdiction.$q$, $q$Municipal code enforcement officers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$Custom Subscription$q$, $q$Custom quote$q$, $q$annual or multi-year contract$q$, NULL, $q$["Configurable civic platform","Permitting and licensing modules","Citizen access portal","GIS integration","Support and implementation services"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$overview$q$, $q$What Is Accela$q$, 2, ARRAY[$q$Accela is a government technology platform providing permitting, licensing, code enforcement, and citizen service software to local and state agencies. Founded in 1999 and headquartered in San Ramon, California, Accela serves several thousand government agencies across the United States and internationally.$q$, $q$Its core product, the Accela Civic Platform, is a configurable system of record for managing building permits, business licensing, environmental health inspections, and code enforcement cases, replacing paper-based or siloed legacy departmental systems.$q$, $q$Accela is unrelated to Accelo, a professional services automation platform for private agencies and consultancies; the two names are similar but the companies serve entirely different markets, government versus private-sector services.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Accela Automation handles permitting and licensing workflows, while Accela Citizen Access provides a public-facing portal where residents and contractors can apply for permits, pay fees, schedule inspections, and track application status online.$q$, $q$Accela GIS ties permits and inspections to interactive maps of regulated parcels, and Accela Asset Management tracks public infrastructure alongside permitting data, while environmental health modules manage inspections for restaurants and other regulated facilities.$q$, $q$Field inspectors use mobile apps to complete and submit inspection results in real time, and reporting dashboards track permit volumes, review times, and departmental performance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('16ab7757-c6c6-454f-853f-f69b743e89cf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Accela does not publish pricing. Costs are individually quoted based on agency size, the number of departments and modules deployed, and integration requirements, typically through a direct sales or public-sector procurement and RFP process.$q$, $q$Contracts are frequently multi-year given typical government procurement cycles, and Accela is also available through government contract vehicles such as Carahsoft, easing purchasing for eligible public-sector buyers.$q$, $q$Because pricing is fully custom, prospective agencies should expect a sales-led evaluation process rather than self-serve signup or published tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Client Work Management$q$, $q$Unify sales, projects, tickets, and retainers around a single client record.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Project Budgeting and Profitability Tracking$q$, $q$Monitor project budgets, timelines, and margins in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Retainer and Contract Management$q$, $q$Track recurring service agreements, usage, and renewal dates automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Time Tracking and Billing$q$, $q$Capture timesheets and expenses and convert them directly into invoices.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Sales CRM and Quoting$q$, $q$Manage leads, proposals, and quotes that convert directly into scheduled project work.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Support Ticketing$q$, $q$Manage client support requests alongside project and billing data in the same system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Resource and Capacity Planning$q$, $q$Forecast team capacity and workload to avoid over- or under-booking staff.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$AI-Powered Insights$q$, $q$AI-assisted project planning and automated flags for at-risk budgets or timelines.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Combines CRM, project management, ticketing, retainers, and billing in one connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Real-time profitability visibility per client and per project$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Strong fit for agencies and consultancies managing many concurrent client engagements$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$AI-assisted capacity planning and risk flagging reduce manual oversight$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Onboarding and implementation support included in contracts$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$No published pricing; requires a sales conversation and custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Minimum user or seat requirements may not suit very small teams or solo freelancers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Breadth of modules can mean a learning curve during onboarding$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Advanced automation and quote-to-cash features cost extra on top of the base platform$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$What is Accelo used for?$q$, $q$Accelo is used by agencies and consultancies to manage the full client services lifecycle, including sales, project delivery, support tickets, retainers, time tracking, and billing, in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$How much does Accelo cost?$q$, $q$Accelo does not publish list pricing. It sells custom subscription quotes based on team size and the modules selected; third-party estimates suggest entry pricing around 20 to 30 dollars per user per month, though this is not officially confirmed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Is Accelo the same company as Accela?$q$, $q$No. Accelo is a professional services automation platform for agencies and consultancies, while Accela is unrelated government permitting and licensing software. The names are similar but the companies are distinct.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$What was Accelo previously called?$q$, $q$Accelo began as AffinityLive, launched in beta by its founding team in Wollongong, Australia, and was rebranded to Accelo in 2015.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Where is Accelo headquartered?$q$, $q$Accelo's primary office is in Denver, Colorado, with additional teams in Wollongong, Australia, and Manila, Philippines.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Who is Accelo built for?$q$, $q$Accelo is built for client-services businesses such as marketing and creative agencies, IT and managed service providers, and consulting firms that bill for time and manage ongoing client relationships.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Does Accelo include billing and invoicing?$q$, $q$Yes, Accelo's Time and Billing module converts timesheets and expenses directly into client invoices tied to project or retainer records.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Does Accelo have AI features?$q$, $q$Yes, Accelo has added AI-powered capabilities for project planning automation, resource capacity forecasting, and identifying at-risk project margins.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Agency Client and Project Management$q$, $q$Marketing and creative agencies use Accelo to manage client relationships, project budgets, and billing from one system instead of stitching together separate CRM, project management, and invoicing tools.$q$, $q$Marketing and creative agency operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Managed IT Services Delivery$q$, $q$IT and managed service providers use Accelo's ticketing and retainer modules to track support requests against contracted service levels and bill clients accurately for recurring work.$q$, $q$MSP and IT services teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Consulting Firm Profitability Tracking$q$, $q$Consulting and professional services firms use Accelo's project and time-tracking data to monitor real-time profitability per client and engagement.$q$, $q$Consulting firm leadership and operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Core (third-party estimate)$q$, $q$Custom quote, estimated $20 to $30 per user per month$q$, $q$monthly, minimum team size applies$q$, NULL, $q$["CRM","Project management","Basic time tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Quote-to-Cash (third-party estimate)$q$, $q$Custom quote, estimated $40 to $60 per user per month$q$, $q$monthly$q$, NULL, $q$["Sales quoting","Project delivery","Billing integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Retainers and Expenses (third-party estimate)$q$, $q$Custom quote, estimated $50 to $70 per user per month$q$, $q$monthly$q$, NULL, $q$["Retainer tracking","Expense management","Advanced billing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$Advanced Automation (third-party estimate)$q$, $q$Custom quote, estimated $70 to $90 per user per month$q$, $q$monthly$q$, NULL, $q$["AI-powered planning","Capacity forecasting","Advanced workflow automation"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$overview$q$, $q$What Is Accelo$q$, 2, ARRAY[$q$Accelo is a professional services automation platform built for agencies, consultancies, and other client-services businesses that need to manage sales, project delivery, support tickets, retainers, and billing in one connected system. The company started as AffinityLive, founded in 2011 by a team in Wollongong, Australia, and rebranded to Accelo in 2015.$q$, $q$Accelo now operates from a primary hub in Denver, Colorado, alongside teams in Australia and the Philippines, and it should not be confused with Accela, an unrelated government permitting and licensing software company despite the similar name.$q$, $q$The platform's central premise is that agencies lose visibility and profit when CRM, project management, ticketing, and billing live in separate disconnected tools; Accelo unifies these around one client record.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Accelo's Sales module handles CRM and quoting, converting proposals directly into scheduled project work, while the Projects module tracks budgets, timelines, and profitability margins in real time.$q$, $q$Tickets manages client support requests, Retainers tracks recurring service agreements and usage against contracted terms, and Time and Billing converts timesheets and expenses directly into client invoices.$q$, $q$More recently, Accelo has added AI-powered capabilities for automating project planning, forecasting team capacity, and flagging at-risk budgets or timelines before they slip.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dfa0f576-375e-4664-990f-e7cd76855a08', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Accelo does not publish list pricing. Costs are quoted based on team size, the modules selected, and growth goals, typically with a minimum number of users required and onboarding support bundled in.$q$, $q$Third-party estimates suggest entry-level pricing around 20 to 30 dollars per user per month, with quote-to-cash and retainer management add-ons pushing costs higher, and advanced automation features reaching 70 to 90 dollars per user per month.$q$, $q$These figures are analyst estimates rather than officially published rates, so prospective buyers should confirm current pricing directly with Accelo's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Managed Drupal Hosting$q$, $q$Auto-scaling, security-hardened cloud infrastructure purpose-built for Drupal sites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Customer Data Platform (Acquia CDP)$q$, $q$Unify first-party customer data across channels to build audience segments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Real-Time Personalization$q$, $q$Deliver personalized content and experiences based on visitor behavior and segment data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Digital Asset Management$q$, $q$Centralize, organize, and distribute brand and marketing assets across teams and sites.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Site Studio$q$, $q$Low-code visual page builder for building and updating Drupal sites without deep developer involvement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Multi-Site Management$q$, $q$Manage large portfolios of Drupal sites and brands from a single platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Security and Compliance Tooling$q$, $q$Automated security patching, monitoring, and compliance support for regulated industries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Marketing Automation$q$, $q$Campaign and email marketing tools that integrate with Acquia's customer data platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Deep, purpose-built expertise in Drupal, backed by the CMS's original creator$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Full digital experience platform spanning hosting, personalization, DAM, and customer data, not just CMS hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Strong fit for large, complex, multi-site, or multi-brand organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Enterprise-grade security, compliance, and auto-scaling infrastructure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Backed by Vista Equity Partners with substantial revenue and an established enterprise customer base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$No published pricing; enterprise contracts typically run into six figures annually$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Requires specialized Drupal expertise to implement and maintain effectively$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Overkill and cost-prohibitive for small or mid-sized organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Sales and procurement cycles are long, typical of enterprise digital experience platform purchases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$What is Acquia?$q$, $q$Acquia is an enterprise digital experience platform company built around the open-source Drupal CMS, offering managed hosting, personalization, customer data, and digital asset management tools for large organizations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Who founded Acquia?$q$, $q$Acquia was founded in 2007 by Dries Buytaert, the original creator of Drupal, along with Jay Batson.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Is Acquia the same as Drupal?$q$, $q$No. Drupal is free, open-source CMS software maintained by a global community. Acquia is a commercial company that provides managed hosting, support, and additional enterprise tools built around Drupal.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$How much does Acquia cost?$q$, $q$Acquia does not publish pricing. Enterprise contracts are individually quoted and, according to industry estimates, commonly run around 100,000 dollars per year or more depending on scope.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Who owns Acquia?$q$, $q$Vista Equity Partners acquired a majority stake in Acquia in 2019.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$What companies use Acquia?$q$, $q$Acquia's customers include large enterprises, universities, and public-sector organizations such as Warner Music Group and Stanford University, among more than 4,000 organizations globally.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$What are Acquia's main products?$q$, $q$Acquia's main products include Acquia Cloud Platform for Drupal hosting, Acquia CDP, Acquia Personalization, Acquia DAM, and Site Studio.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$What are Acquia's main competitors?$q$, $q$Acquia competes with other enterprise digital experience platform and CMS vendors such as Adobe Experience Manager, Sitecore, and Contentful.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Enterprise Drupal Hosting and Management$q$, $q$Large organizations running mission-critical Drupal websites use Acquia Cloud Platform for auto-scaling, secure, compliant hosting with expert Drupal support.$q$, $q$Enterprise IT and digital teams running Drupal$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Unified Customer Data and Personalization$q$, $q$Global brands use Acquia CDP and Personalization to unify customer data across channels and deliver tailored content and offers in real time.$q$, $q$Enterprise marketing and customer experience teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Multi-Site, Multi-Brand Web Management$q$, $q$Universities, government agencies, and multi-brand companies use Acquia Site Studio to manage large portfolios of websites from a single platform with consistent governance.$q$, $q$Public-sector and multi-brand enterprise web teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$Enterprise Platform$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Managed Drupal hosting","Security and compliance tooling","Auto-scaling infrastructure","Support SLAs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$DXP Suite Add-Ons$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Acquia CDP","Personalization","Digital Asset Management","Site Studio","Marketing automation"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$overview$q$, $q$What Is Acquia$q$, 2, ARRAY[$q$Acquia is an enterprise digital experience platform company built around Drupal, the open-source CMS co-created by Acquia's founder Dries Buytaert. Founded in 2007 and headquartered in Boston, Massachusetts, Acquia provides the managed infrastructure, support, and enterprise tooling that large organizations need to run Drupal at scale.$q$, $q$Vista Equity Partners acquired a majority stake in Acquia in 2019, and the company now serves more than 4,000 organizations globally, including universities, government agencies, and global consumer brands, reportedly generating over 350 million dollars in annual revenue.$q$, $q$Beyond Drupal hosting, Acquia has expanded into a full digital experience platform spanning customer data, personalization, digital asset management, and marketing automation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Acquia Cloud Platform provides auto-scaling, security-hardened hosting purpose-built for Drupal, while Acquia CDP unifies first-party customer data across channels to build audience segments for personalization.$q$, $q$Acquia Personalization delivers real-time tailored content and experiences based on visitor behavior and segment data, and Acquia DAM centralizes brand and marketing assets across teams and sites.$q$, $q$Site Studio offers a low-code visual page builder for updating Drupal sites without deep developer involvement, and the platform supports multi-site management for organizations running large portfolios of Drupal properties.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d516653b-2737-45ee-86a3-367d5934432c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Acquia does not publish pricing. Contracts are individually quoted based on the specific products selected, traffic volume, number of sites, and support tier required, following a traditional enterprise sales process.$q$, $q$Industry estimates put typical enterprise contracts around 100,000 dollars per year or more, reflecting both the platform's scope and the specialized Drupal expertise needed to implement and maintain it.$q$, $q$Additional DXP modules such as CDP, Personalization, DAM, and Site Studio are typically sold as modular add-ons on top of the core hosting platform, adding to the total contract value based on an organization's needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Style Guide Enforcement$q$, $q$Checks content in real time against a company's custom style guide and grammar rules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Terminology Management$q$, $q$Flags non-preferred terms and enforces approved terminology across all content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Tone and Clarity Scoring$q$, $q$Scores content for tone consistency and readability to match brand voice guidelines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$AI Content Governance$q$, $q$Reviews and corrects AI-generated drafts to ensure compliance with brand and regulatory standards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Native Integrations$q$, $q$Works inside Word, Google Docs, Adobe FrameMaker, Confluence, Salesforce, Zendesk, and other authoring tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Content Analytics Dashboards$q$, $q$Track content quality trends, terminology compliance, and readability across teams and languages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Multi-Language Support$q$, $q$Supports content governance checks across multiple languages for global content teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$API and Pipeline Integration$q$, $q$Embed content quality checks into custom workflows and automated publishing pipelines.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Deep enterprise-grade terminology and style guide customization beyond generic grammar checking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Wide range of native integrations into existing authoring and content management tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Addresses a real governance gap created by AI-generated drafting content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Strong analytics for content operations and localization teams to measure quality at scale$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Established enterprise customer base including major regulated and global brands$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Pricing is not published and enterprise deals require a sales process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Overkill and cost-prohibitive for small teams or individual writers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Requires upfront investment in defining style guides and terminology to get full value$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Smaller company size relative to larger writing-assistant competitors may mean slower feature velocity$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$What is Acrolinx used for?$q$, $q$Acrolinx is used by large organizations to enforce writing style, tone, terminology, and brand consistency across all their written content, including checking AI-generated drafts before publication.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$How is Acrolinx different from Grammarly?$q$, $q$Grammarly focuses on general grammar and style suggestions for individual writers, while Acrolinx is built for enterprise content operations teams, offering deep customization of style guides, terminology databases, and analytics across large volumes of content and multiple languages.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Does Acrolinx check AI-generated content?$q$, $q$Yes, Acrolinx has expanded to specifically govern AI-generated content, checking it against brand voice, terminology, and regulatory language requirements before it is published.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$What tools does Acrolinx integrate with?$q$, $q$Acrolinx integrates with Microsoft Word, Google Docs, Adobe FrameMaker, Confluence, Salesforce, Zendesk, and other authoring and content management platforms, plus a web sidebar and API.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$How much does Acrolinx cost?$q$, $q$Acrolinx does not publish pricing. Costs are quoted individually based on user count, languages, and integrations, with third-party estimates suggesting starting costs in the low thousands of dollars per month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$When was Acrolinx founded?$q$, $q$Acrolinx was founded in 2002 as a spin-off from the German Research Center for Artificial Intelligence in Berlin.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Who are Acrolinx's customers?$q$, $q$Acrolinx's customers include large enterprises such as Microsoft, Dell, Google, Citi, and Nike.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Where is Acrolinx headquartered?$q$, $q$Acrolinx is headquartered in Berlin, Germany, with a significant office presence in Boston, Massachusetts.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Enterprise Documentation Consistency$q$, $q$Technical writing teams use Acrolinx inside FrameMaker and Confluence to enforce terminology and style consistency across large volumes of product documentation.$q$, $q$Technical writing and documentation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Marketing Brand Voice Compliance$q$, $q$Global marketing teams use Acrolinx to ensure copy across regions and channels stays consistent with brand voice and tone guidelines before publication.$q$, $q$Enterprise marketing and brand teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$AI-Generated Content Governance$q$, $q$Content teams using generative AI to draft articles or support content use Acrolinx to review and correct AI output against style guides and regulatory language before it goes live.$q$, $q$Content operations teams adopting generative AI$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$Enterprise$q$, $q$Custom quote, third-party estimates suggest starting around $1,000 or more per month$q$, $q$annual contract$q$, NULL, $q$["Style guide and terminology enforcement","Native tool integrations","Content analytics","Multi-language support","API access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$overview$q$, $q$What Is Acrolinx$q$, 2, ARRAY[$q$Acrolinx is an AI-powered content governance platform that helps large organizations enforce writing style, tone, terminology, and brand consistency across all their written content, including content drafted with generative AI. Founded in 2002 as a spin-off from the German Research Center for Artificial Intelligence in Berlin, the company remains headquartered there with a significant US office in Boston.$q$, $q$Its founders, Dr. Andrew Bredenkamp, Sabine Lehmann, and Professor Hans Uszkoreit, built the company on computational linguistics research, and Acrolinx now employs roughly 180 people and counts EMH Partners as a minority investor.$q$, $q$As generative AI adoption has grown, Acrolinx has repositioned itself specifically around governing AI-generated content, ensuring drafts produced by large language models still comply with brand voice and regulatory language requirements before publication.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Acrolinx's linguistic analysis engine checks content in real time against a company's defined style guide, terminology list, and tone-of-voice rules, scoring content and flagging specific issues as writers type.$q$, $q$The platform integrates directly into authoring tools including Microsoft Word, Google Docs, Adobe FrameMaker, Confluence, Salesforce, and Zendesk, plus a standalone web sidebar and API access for embedding checks into custom workflows.$q$, $q$Analytics dashboards let content operations and localization teams measure quality trends, terminology compliance, and readability across thousands of documents and multiple languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05200050-aef1-41d1-8a4c-687d3c1ab299', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Acrolinx does not publish self-serve pricing. Deals are quoted individually based on the number of users, languages supported, and integrations required, following an enterprise sales process.$q$, $q$Third-party analyst estimates suggest starting costs in the low thousands of dollars per month for smaller deployments, with larger enterprise rollouts priced significantly higher based on scope.$q$, $q$Because pricing is entirely custom, prospective customers should expect a sales-led evaluation rather than published tiers or self-serve checkout.$q$]::text[], 2);
