-- ── Absorb LMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based corporate learning management system that helps organizations deliver, track, and report on employee, customer, and partner training at scale.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Calgary, Alberta, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Absorb LMS Review: Learning Management System Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Absorb LMS is a cloud learning management system for corporate training and compliance. See pricing structure, features, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Absorb LMS is a cloud-based learning management system built for corporate training, compliance, partner and customer education, and extended enterprise learning programs. Founded in 2003 and headquartered in Calgary, Alberta, Canada, Absorb Software, the company behind Absorb LMS, serves more than 3,500 organizations worldwide through offices across North America, Europe, and Asia-Pacific, and has raised roughly 59 million dollars in funding to date. The platform lets administrators create, organize, and assign online courses, instructor-led training, and blended learning paths, then track completions, certifications, and compliance requirements through built-in reporting and dashboards. Absorb LMS supports SCORM, xAPI (Tin Can), and AICC content standards, so organizations can import existing e-learning courses from authoring tools, and it includes a native course authoring tool, Absorb Create, for building lightweight lessons directly inside the platform. The system is used both for internal employee training, such as onboarding and compliance, and for external audiences such as customers, channel partners, and franchisees, with the option to run branded, multi-tenant portals for different audiences from one instance. Absorb has invested heavily in AI-assisted features in recent years, including AI-generated course descriptions and content summaries, automated skills mapping, and intelligent content recommendations that surface relevant courses to learners based on role and prior activity. Other platform capabilities include gamification such as badges, leaderboards, and points, social and collaborative learning tools, native mobile apps for iOS and Android with offline access, e-commerce for selling courses and certifications, and integrations with HRIS platforms, single sign-on providers, video conferencing tools, and content marketplaces. Absorb LMS is sold in tiered editions, commonly referenced as Core, Pro, and Enterprise, with pricing quoted per active learner per year rather than published as a fixed rate. The company does not publish list pricing and requires prospects to request a custom quote based on learner count, deployment complexity, and the feature set required. Third-party spend-benchmarking data suggests small and mid-sized deployments average in the tens of thousands of dollars per year, with enterprise deployments considerably higher. The platform is positioned primarily at mid-market and enterprise buyers in industries such as healthcare, financial services, manufacturing, and non-profits that need auditable compliance training alongside general skills development, competing with LMS vendors like Cornerstone OnDemand, Docebo, TalentLMS, and 360Learning.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae54ef19-4ee9-49ce-8b0c-384fc84052de';

