-- ── Abstract ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Design version control and collaboration platform that lets design teams track, branch, and review changes to Sketch and Figma files the way developers use Git.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; paid plans from $29/month per contributor billed annually$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Abstract Review: Design Version Control Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Abstract brings Git-style version control and review workflows to Sketch and Figma design files. See pricing, features, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Abstract, sold from goabstract.com, is a design version control and collaboration platform originally built to bring Git-like branching, merging, and version history to Sketch design files, and later expanded into a broader design operations tool called Notebooks. Founded in 2016 and headquartered in San Francisco, Abstract set out to solve a problem common in design teams before component-based tools like Figma matured: multiple designers editing the same file with no reliable way to track changes, compare versions, or review work before merging it into a shared library. The company raised institutional funding, including a 30 million dollar round reported by TechCrunch in 2019, and says its tools have been used by more than 7,000 companies, including roughly a third of the Fortune 500. Abstract's product today spans two distinct offerings. Branches is the original product: it layers Git-style version control on top of Sketch files, letting designers create branches for exploratory work, request reviews from teammates, leave inline comments, and merge approved changes into a master file, all with a visual diff and full version history. Notebooks is a newer, broader workspace for documenting and reviewing design work that integrates with Figma, Sketch, GitHub, and Jira, letting teams track design decisions, gather structured feedback, and connect design artifacts to engineering tickets regardless of which design tool was used to create them. Pricing is per-contributor and billed monthly or annually, with viewers included at no extra charge on every plan. Abstract offers a free-forever tier for individuals or small teams experimenting with up to three active notebooks, a Pro tier priced around 29 to 35 dollars per contributor per month depending on the product line, and an Enterprise tier with custom pricing that adds SSO/SAML, unlimited storage, dedicated account management, and advanced reporting. Abstract's target audience is product design teams at mid-size and large companies who need structured version control, review workflows, and documentation around their design process, especially organizations with compliance or audit requirements around design decisions. It competes with native version history in Figma, as well as tools like Zeplin and Avocode, and with Figma's own branching features, which have reduced the unique value of Sketch-specific version control since Figma's rise to dominance in the design tool market. Abstract is completely unrelated to Abstract API, a developer API company with a similarly generic name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4faf985-7c58-4c87-8560-524d88331992';

